from dataclasses import dataclass

@dataclass
class Triple:
    subject: str
    predicate: str
    object: str

# EVOLVE-BLOCK-START

def predict(triples: list[Triple]) -> str:
    subject_map = {}
    for triple in triples:
        if triple.subject not in subject_map:
            subject_map[triple.subject] = []
        subject_map[triple.subject].append((triple.predicate, triple.object))

    sentence = ""
    for subject, triples in subject_map.items():
        if sentence:
            sentence += " which "
        sentence += f"{subject} "
        predicates = []
        for i, (predicate, obj) in enumerate(triples):
            normalized_pred = predicate.replace('1stRunway', 'first runway').replace('2ndRunway', 'second runway').replace('3rdRunway', 'third runway').replace('4thRunway', 'fourth runway').replace('5thRunway', 'fifth runway').replace('Length', ' length').replace('SurfaceType', ' surface type').replace('AboveTheSeaLevel', ' above sea level').replace('LocationIdentifier', ' identifier').replace('Iata', 'IATA').replace('Icao', 'ICAO').replace('InFeet', ' in feet').replace('InMetres', ' in metres')
            if predicate in ["cityServed", "mayor", "isPartOf", "operatingOrganisation", "location", "country", "capital", "language", "leader", "owner"]:
                predicates.append(f"{normalized_pred} of {obj}")
            elif predicate in ["elevationAboveTheSeaLevel", "elevationAboveTheSeaLevelInFeet", "elevationAboveTheSeaLevelInMetres"]:
                predicates.append(f"at an elevation of {obj}")
            elif predicate in ["runwayLength", "1stRunwayLengthFeet", "3rdRunwayLengthFeet"]:
                predicates.append(f"with a {normalized_pred} of {obj}")
            elif predicate in ["icaoLocationIdentifier", "iataLocationIdentifier", "locationIdentifier"]:
                predicates.append(f"identified by {obj}")
            elif predicate in ["nativeName", "leaderParty", "runwayName", "runwaySurfaceType"]:
                predicates.append(f"with a {normalized_pred} of {obj}")
            else:
                predicates.append(f"has a {normalized_pred} of {obj}")

        if predicates:
            location_predicates = []
            other_predicates = []
            for p in predicates:
                if any(phrase in p for phrase in ["is located in", "is part of", "serves the city of", "is operated by", "has as its capital", "has as its official language", "has as its leader"]):
                    location_predicates.append(p)
                else:
                    other_predicates.append(p)

            all_predicates = location_predicates + other_predicates
            if len(all_predicates) > 1:
                sentence += ", ".join(all_predicates[:-1]) + " and " + all_predicates[-1]
            else:
                sentence += all_predicates[0]

    return sentence + "."

